// src/components/shared/TaskModal.jsx
import { useState, useEffect } from "react";
import { userAPI, projectAPI } from "../../utils/api";
import { todayISO } from "../../utils/helpers";

const STATUSES = ["To Do","In Progress","Done","Hold"];

export default function TaskModal({ task, currentUser, onClose, onSave, loading }) {
  const [interns,  setInterns]  = useState([]);
  const [projects, setProjects] = useState([]);
  const [form, setForm] = useState(
    task || {
      date: todayISO(), project:"EGI", assignedBy:currentUser.name,
      assignedTo: currentUser.role==="intern" ? currentUser.id : "",
      task:"", status:"To Do", estimateTime:"",
      timeFrom:"", timeTo:"", totalMinutes:"", workDoc:"", reason:"",
    }
  );

  useEffect(() => {
    if (currentUser.role === "supervisor") {
      userAPI.getAll("intern").then(d => setInterns(d.users || [])).catch(()=>{});
    }
    projectAPI.getAll().then(d => setProjects(d.projects || [])).catch(()=>{});
  }, [currentUser.role]);

  const set = (k,v) => setForm(f=>({...f,[k]:v}));

  return (
    <div className="modal-overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal animate-scaleIn">
        <div className="modal-header">
          <div>
            <div className="modal-title">{task?"✏️ Edit Task":"➕ Create New Task"}</div>
            <p className="text-sm text-gray" style={{marginTop:3}}>{task?"Update task details below.":"Fill in the details to assign a new task."}</p>
          </div>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <div className="form-grid">
            <div className="form-group">
              <label className="form-label">Date</label>
              <input className="form-input" type="date" value={form.date} onChange={e=>set("date",e.target.value)}/>
            </div>
            <div className="form-group">
              <label className="form-label">Project</label>
              <select className="form-select" value={form.project} onChange={e=>set("project",e.target.value)}>
                {projects.map(p=><option key={p.id} value={p.name}>{p.name} – {p.fullName}</option>)}
                {projects.length===0 && ["EGI","HOC","GRN"].map(n=><option key={n}>{n}</option>)}
              </select>
            </div>
            {currentUser.role==="supervisor" && (
              <div className="form-group">
                <label className="form-label">Assign To</label>
                <select className="form-select" value={form.assignedTo} onChange={e=>set("assignedTo",parseInt(e.target.value))}>
                  <option value="">Select intern…</option>
                  {interns.map(i=><option key={i.id} value={i.id}>{i.name}</option>)}
                </select>
              </div>
            )}
            <div className="form-group">
              <label className="form-label">Status</label>
              <select className="form-select" value={form.status} onChange={e=>set("status",e.target.value)}>
                {STATUSES.map(s=><option key={s}>{s}</option>)}
              </select>
            </div>
            <div className="form-group full">
              <label className="form-label">Task / Work Description</label>
              <textarea className="form-textarea" rows={3} value={form.task} onChange={e=>set("task",e.target.value)} placeholder="Describe the task in detail…"/>
            </div>
            <div className="form-group">
              <label className="form-label">Estimate Time</label>
              <input className="form-input" value={form.estimateTime} onChange={e=>set("estimateTime",e.target.value)} placeholder="e.g. 2 Hours, 30 min"/>
            </div>

            <div className="form-group full">
              <label className="form-label">Work Document / Link</label>
              <input className="form-input" value={form.workDoc} onChange={e=>set("workDoc",e.target.value)} placeholder="https://drive.google.com/…"/>
            </div>
            {form.status==="Hold" && (
              <div className="form-group full">
                <label className="form-label">Reason for Not Completing</label>
                <textarea className="form-textarea" rows={2} value={form.reason} onChange={e=>set("reason",e.target.value)} placeholder="Explain why this task is on hold…"/>
              </div>
            )}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={()=>onSave(form)} disabled={loading}>
            {loading?"Saving…": task?"Update Task":"Create Task"}
          </button>
        </div>
      </div>
    </div>
  );
}
